const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  let rawUrl = (d.source_url || '').trim();

  // 🚫 Empty URL
  if (!rawUrl) {
    results.push({
      json: {
        ...d,
        normalized_url: null,
        linkedin_username: null,
        norm_status: 'skipped_empty',
        stage: 'S2_FAILED'
      }
    });
    continue;
  }

  try {
    // ✅ Step 1: Normalize case
    let url = rawUrl.toLowerCase().trim();

    // ✅ Step 2: Remove protocol
    url = url.replace(/^https?:\/\//, '');

    // ✅ Step 3: Remove www
    url = url.replace(/^www\./, '');

    // ✅ Step 4: Ensure it's LinkedIn profile
    if (!url.includes('linkedin.com/in/')) {
      results.push({
        json: {
          ...d,
          normalized_url: null,
          linkedin_username: null,
          norm_status: 'invalid_not_linkedin',
          stage: 'S2_FAILED'
        }
      });
      continue;
    }

    // ✅ Step 5: Extract username safely
    const match = url.match(/linkedin\.com\/in\/([^\/\?\#]+)/);

    if (!match || !match[1]) {
      results.push({
        json: {
          ...d,
          normalized_url: null,
          linkedin_username: null,
          norm_status: 'no_username',
          stage: 'S2_FAILED'
        }
      });
      continue;
    }

    const username = match[1];

    // ✅ Step 6: Build clean canonical URL
    const normalizedUrl = `https://www.linkedin.com/in/${username}/`;

    results.push({
      json: {
        ...d,
        normalized_url: normalizedUrl,
        linkedin_username: username,
        norm_status: 'normalized',
        stage: 'S3'
      }
    });

  } catch (e) {
    results.push({
      json: {
        ...d,
        normalized_url: null,
        linkedin_username: null,
        norm_status: 'error: ' + e.message,
        stage: 'S2_FAILED'
      }
    });
  }
}

return results;

const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;

  // Generate learner_id if missing
  let learnerId = d.learner_id;

  if (!learnerId || learnerId === '') {
    // Promote valid URL record from S2 to S3
    // Generate ID from username
    const username = (d.linkedin_username ||
      d.normalized_url
        .replace('https://www.linkedin.com/in/', '')
        .replace('/', '')
    );
    learnerId = 'LRN-' + 
      username.toUpperCase()
        .replace(/[^A-Z0-9]/g, '')
        .substring(0, 8) +
      '-' + Date.now().toString().slice(-4);
  }

  results.push({
    json: {
      ...d,
      learner_id: learnerId,
      id_repaired: !d.learner_id,
      stage: 'S3'
    }
  });
}

return results;

const items = $input.all();
const results = [];

// Group by normalized_url
const groups = {};
for (const item of items) {
  const url = item.json.normalized_url;
  if (!groups[url]) groups[url] = [];
  groups[url].push(item.json);
}

for (const [url, records] of Object.entries(groups)) {
  // Sort by created_at — oldest is primary
  records.sort((a, b) =>
    new Date(a.created_at) - new Date(b.created_at)
  );

  const primary = records[0];

  for (let i = 0; i < records.length; i++) {
    const rec = records[i];
    const isPrimary = i === 0;

    results.push({
      json: {
        ...rec,
        is_duplicate: !isPrimary,
        primary_record_id: primary.record_id,
        duplicate_group: url,
        stage: 'S4',
        updated_at: new Date().toISOString()
      }
    });
  }
}

return results;

