const items = $input.all();
const results = [];

for (const item of items) {
  const d = item.json;
  const issues = [];

  // CRM readiness checks
  if (!d.full_name) issues.push('missing_name');
  if (!d.email) issues.push('missing_email');
  if (!d.normalized_url) issues.push('missing_url');
  if (!d.learner_id) issues.push('missing_id');

  const isReady = issues.length === 0;

  results.push({
    json: {
      ...d,
      crm_ready: isReady,
      crm_issues: issues.join(', '),
      stage: isReady ? 'S6' : 'S5_FAILED',
      updated_at: new Date().toISOString()
    }
  });
}

return results;
